interface Props extends HTMLAttributes<"div"> {
  class?: string;
}

const { class: className = "", ...rest } = Astro.props as Props;
---

<div
  {...rest}
  data-slot="navigation-menu-indicator"
  class={cn(
    "rounded-none data-[state=visible]:animate-in data-[state=hidden]:animate-out data-[state=hidden]:fade-out data-[state=visible]:fade-in absolute left-0 top-0 z-0 pointer-events-none opacity-0 data-instant:transition-opacity transition-[translate,width,height] duration-150 ease data-[state=visible]:opacity-100",
    "translate-x-(--indicator-left,0px) translate-y-(--indicator-top,0px)",
    "w-(--indicator-width,0) h-(--indicator-height,0)",
    className,
  )}
>
  <div class="bg-muted/60 ring-border/40 ring-1 absolute inset-0 rounded-[inherit]"></div>
  <div class="hidden bg-border rounded-none shadow-md absolute top-full left-1/2 h-2 w-2 -translate-x-1/2 -translate-y-[40%] rotate-45"></div>
</div>

