import type { HTMLAttributes } from "astro/types";
import { cva } from "class-variance-authority";
import { cn } from "@/lib/utils";
import SemanticIcon from "../icon/SemanticIcon.astro";

interface Props extends HTMLAttributes<"button"> {
  class?: string;
}

export const navigationMenuTriggerStyle = cva(
  "navigation-menu-trigger-surface bg-background hover:bg-muted focus:bg-muted data-open:hover:bg-muted data-open:focus:bg-muted data-open:bg-muted/50 focus-visible:ring-ring/50 data-popup-open:bg-muted/50 data-popup-open:hover:bg-muted rounded-none px-2.5 py-1.5 text-xs font-medium transition-all focus-visible:ring-1 focus-visible:outline-1 disabled:opacity-50 group/navigation-menu-trigger inline-flex h-9 w-max items-center justify-center outline-none disabled:pointer-events-none relative z-1",
);

const {
  class: className = "",
  type = "button",
  ...rest
} = Astro.props as Props;
---

<button
  {...rest}
  data-slot="navigation-menu-trigger"
  type={type}
  class={cn(navigationMenuTriggerStyle(), "group", className)}
>
  <slot />
  <SemanticIcon
    name="chevron-down"
    class="relative top-px ml-1 size-3 transition duration-300 group-data-open/navigation-menu-trigger:rotate-180 group-data-popup-open/navigation-menu-trigger:rotate-180"
    aria-hidden="true"
  />
</button>

