import type { HTMLAttributes } from "astro/types";
import { cn } from "@/lib/utils";

interface Props extends HTMLAttributes<"div"> {
  class?: string;
}

const { class: className = "", ...rest } = Astro.props as Props;
---

<div
  data-slot="navigation-menu-viewport-positioner"
  class={cn("", 
    "isolate z-50 transition-[left,top] duration-250 ease data-ending-style:opacity-0",
  )}
>
  <div
    {...rest}
    data-slot="navigation-menu-viewport"
    class={cn("bg-popover text-popover-foreground data-open:animate-in data-open:zoom-in-90 ring-foreground/10 rounded-none shadow ring-1 duration-100", 
      "bg-popover shadow-lg rounded-lg outline outline-border overflow-clip",
      "w-(--viewport-width,0) h-(--viewport-height,0)",
      "origin-(--transform-origin)",
      "duration-250 ease data-instant:transition-[scale,opacity] transition-[width,height,transform,scale,opacity]",
      "data-[state=open]:opacity-100 data-[state=open]:pointer-events-auto",
      "data-instant:data-[state=open]:animate-in data-instant:data-[state=open]:fade-in data-instant:data-[state=open]:zoom-in-95",
      "data-ending-style:opacity-0 data-ending-style:scale-90",
      "will-change-[width,height,transform]",
      className,
    )}
  >
  </div>
</div>

export { default as NavigationMenu } from "./NavigationMenu.astro";
export { default as NavigationMenuList } from "./NavigationMenuList.astro";
export { default as NavigationMenuItem } from "./NavigationMenuItem.astro";
export { default as NavigationMenuTrigger } from "./NavigationMenuTrigger.astro";
export { default as NavigationMenuContent } from "./NavigationMenuContent.astro";
export { default as NavigationMenuViewport } from "./NavigationMenuViewport.astro";
export { default as NavigationMenuLink } from "./NavigationMenuLink.astro";
export { default as NavigationMenuIndicator } from "./NavigationMenuIndicator.astro";
export { navigationMenuTriggerStyle } from "./NavigationMenuTrigger.astro";
